import{_ as s,o as a,c as t,e as p}from"./app-83da4608.js";const e={};function o(c,n){return a(),t("div",null,[...n[0]||(n[0]=[p(`<h1 id="_5-1-nest-js-后端性能优化与微服务架构" tabindex="-1"><a class="header-anchor" href="#_5-1-nest-js-后端性能优化与微服务架构" aria-hidden="true">#</a> 5.1 Nest.js 后端性能优化与微服务架构</h1><p>当我们的 AI Agent 平台开始服务于真实的企业客户时，并发量的增加和庞大文本数据的分析请求会让单体架构（Monolith）面临严峻挑战。大模型（如 OpenAI、Claude）API 的调用通常是耗时且昂贵的。</p><p>为了提升系统的响应速度、降低 API 成本，并为未来的水平扩展做好准备，本节我们将结合现有项目，深入探讨并实战 <strong>Redis 缓存优化</strong> 与 <strong>Nest.js 微服务架构</strong>。</p><h2 id="_1-性能优化-引入-redis-缓存机制" tabindex="-1"><a class="header-anchor" href="#_1-性能优化-引入-redis-缓存机制" aria-hidden="true">#</a> 1. 性能优化：引入 Redis 缓存机制</h2><p>在数据分析场景中，用户可能会多次请求分析相同或高度相似的数据。如果每次都直接调用 LLM，不仅会导致用户面临漫长的等待，还会产生大量的重复 Token 消耗。</p><p><strong>优化方案：基于内容的哈希缓存</strong></p><p>在我们的项目中，我们通过引入 <code>@nestjs/cache-manager</code> 和 <code>cache-manager-redis-yet</code>，结合现有的 Redis 基础设施，实现了一套高效的缓存层。</p><h3 id="_1-1-全局缓存模块配置" tabindex="-1"><a class="header-anchor" href="#_1-1-全局缓存模块配置" aria-hidden="true">#</a> 1.1 全局缓存模块配置</h3><p>首先，在 <code>app.module.ts</code> 中，我们利用 <code>ConfigService</code> 异步注册了全局的 <code>CacheModule</code>，并将其连接到 Redis：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// backend/src/app.module.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> CacheModule <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/cache-manager&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> redisStore <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;cache-manager-redis-yet&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Module</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  imports<span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token comment">// ... 其他模块</span>
    CacheModule<span class="token punctuation">.</span><span class="token function">registerAsync</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      isGlobal<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
      inject<span class="token operator">:</span> <span class="token punctuation">[</span>ConfigService<span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token function-variable function">useFactory</span><span class="token operator">:</span> <span class="token keyword">async</span> <span class="token punctuation">(</span>configService<span class="token operator">:</span> ConfigService<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
        <span class="token keyword">const</span> store <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">redisStore</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
          socket<span class="token operator">:</span> <span class="token punctuation">{</span>
            host<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;REDIS_HOST&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;localhost&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
            port<span class="token operator">:</span> <span class="token function">Number</span><span class="token punctuation">(</span>configService<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;REDIS_PORT&#39;</span><span class="token punctuation">,</span> <span class="token number">6379</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
          <span class="token punctuation">}</span><span class="token punctuation">,</span>
        <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token punctuation">{</span>
          store<span class="token punctuation">,</span>
          ttl<span class="token operator">:</span> <span class="token number">3600000</span><span class="token punctuation">,</span> <span class="token comment">// 默认 1 小时缓存 (ms)</span>
        <span class="token punctuation">}</span><span class="token punctuation">;</span>
      <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AppModule</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-核心业务的缓存拦截" tabindex="-1"><a class="header-anchor" href="#_1-2-核心业务的缓存拦截" aria-hidden="true">#</a> 1.2 核心业务的缓存拦截</h3><p>在 <code>AnalysisService</code> 中，我们为核心的 <code>analyzeText</code> 方法添加了缓存逻辑。为了确保缓存键的唯一性和长度可控，我们对预处理后的长文本计算 SHA-256 哈希值作为 Redis Key。</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// backend/src/analysis/analysis.service.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> <span class="token constant">CACHE_MANAGER</span> <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/cache-manager&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token keyword">type</span> <span class="token punctuation">{</span> Cache <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;cache-manager&#39;</span><span class="token punctuation">;</span> <span class="token comment">// 注意：使用 type-only import 避免编译报错</span>
<span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> crypto <span class="token keyword">from</span> <span class="token string">&#39;crypto&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisService</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span>
    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Inject</span></span><span class="token punctuation">(</span><span class="token string">&#39;LLM_SERVICE&#39;</span><span class="token punctuation">)</span> <span class="token keyword">private</span> <span class="token keyword">readonly</span> llmService<span class="token operator">:</span> ILLMService<span class="token punctuation">,</span>
    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Inject</span></span><span class="token punctuation">(</span><span class="token constant">CACHE_MANAGER</span><span class="token punctuation">)</span> <span class="token keyword">private</span> cacheManager<span class="token operator">:</span> Cache<span class="token punctuation">,</span>
  <span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token keyword">private</span> <span class="token function">generateHash</span><span class="token punctuation">(</span>content<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">string</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> crypto<span class="token punctuation">.</span><span class="token function">createHash</span><span class="token punctuation">(</span><span class="token string">&#39;sha256&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">update</span><span class="token punctuation">(</span>content<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">digest</span><span class="token punctuation">(</span><span class="token string">&#39;hex&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">async</span> <span class="token function">analyzeText</span><span class="token punctuation">(</span>rawContent<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> cleanContent <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">preprocessText</span><span class="token punctuation">(</span>rawContent<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 1. 生成基于内容哈希的缓存 Key</span>
    <span class="token keyword">const</span> cacheKey <span class="token operator">=</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">analysis:text:</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">generateHash</span><span class="token punctuation">(</span>cleanContent<span class="token punctuation">)</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">;</span>
    
    <span class="token comment">// 2. 检查缓存是否命中</span>
    <span class="token keyword">const</span> cachedResult<span class="token operator">:</span> <span class="token builtin">string</span> <span class="token operator">|</span> <span class="token keyword">undefined</span> <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>cacheManager<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>cacheKey<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>cachedResult<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">🎯 命中缓存，直接返回之前的分析结果！Key: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>cacheKey<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token keyword">return</span> cachedResult<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// 3. 缓存未命中，调用大模型</span>
    <span class="token keyword">const</span> prompt <span class="token operator">=</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">你是一个专业的数据分析专家... \\n\\n&quot;&quot;&quot;\\n</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>cleanContent<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">\\n&quot;&quot;&quot;</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> aiResult <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>llmService<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span>prompt<span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token comment">// 4. 将结果存入 Redis，设置过期时间</span>
    <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>cacheManager<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>cacheKey<span class="token punctuation">,</span> aiResult<span class="token punctuation">,</span> <span class="token number">3600000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">💾 结果已存入缓存。Key: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>cacheKey<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">return</span> aiResult<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过这套机制，相同的分析请求响应时间将从几秒、十几秒骤降至几毫秒，极大地提升了用户体验并节省了成本。</p><h2 id="_2-架构演进-走向微服务-microservices" tabindex="-1"><a class="header-anchor" href="#_2-架构演进-走向微服务-microservices" aria-hidden="true">#</a> 2. 架构演进：走向微服务 (Microservices)</h2><p>目前我们的 <code>backend</code> 是一个单体应用，所有的模块（分析、网关、数据库连接、后台任务）都在一个进程里运行。随着业务发展，特别是 AI 分析这种 CPU 和网络 I/O 密集型的任务，很容易拖垮整个系统的 HTTP 响应能力。</p><p>Nest.js 原生支持 <code>@nestjs/microservices</code>。我们可以将系统改造为<strong>混合应用 (Hybrid Application)</strong>，即同时监听 HTTP 请求和微服务消息。</p><h3 id="_2-1-开启微服务监听-redis-传输层" tabindex="-1"><a class="header-anchor" href="#_2-1-开启微服务监听-redis-传输层" aria-hidden="true">#</a> 2.1 开启微服务监听 (Redis 传输层)</h3><p>在我们的项目中，为了不引入额外的中间件负担，我们复用了现有的 Redis 作为微服务之间的消息传输层 (Transport)。在 <code>main.ts</code> 中，我们配置并启动了微服务：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// backend/src/main.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Transport<span class="token punctuation">,</span> MicroserviceOptions <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/microservices&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">bootstrap</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token keyword">await</span> NestFactory<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>AppModule<span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> configService <span class="token operator">=</span> app<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>ConfigService<span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 开启微服务监听 (混合应用模式)</span>
  app<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">connectMicroservice</span><span class="token generic class-name"><span class="token operator">&lt;</span>MicroserviceOptions<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
    transport<span class="token operator">:</span> Transport<span class="token punctuation">.</span><span class="token constant">REDIS</span><span class="token punctuation">,</span>
    options<span class="token operator">:</span> <span class="token punctuation">{</span>
      host<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;REDIS_HOST&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;localhost&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
      port<span class="token operator">:</span> <span class="token function">Number</span><span class="token punctuation">(</span>configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">number</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;REDIS_PORT&#39;</span><span class="token punctuation">,</span> <span class="token number">6379</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// ... 其他 HTTP 配置 (CORS, Pipes 等)</span>

  <span class="token keyword">await</span> app<span class="token punctuation">.</span><span class="token function">startAllMicroservices</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 启动微服务</span>
  <span class="token keyword">new</span> <span class="token class-name">Logger</span><span class="token punctuation">(</span><span class="token string">&#39;Bootstrap&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Microservice is listening via Redis transport</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token keyword">await</span> app<span class="token punctuation">.</span><span class="token function">listen</span><span class="token punctuation">(</span>port<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-暴露微服务接口" tabindex="-1"><a class="header-anchor" href="#_2-2-暴露微服务接口" aria-hidden="true">#</a> 2.2 暴露微服务接口</h3><p>在 Controller 层，我们不仅可以暴露 <code>@Post</code>、<code>@Get</code> 等 HTTP 装饰器，还可以使用 <code>@MessagePattern</code> 来暴露微服务接口。这意味着其他服务（如独立部署的 API 网关）可以通过 Redis 向我们的 AI 分析服务发送指令，而无需走 HTTP 协议。</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// backend/src/analysis/analysis.controller.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> MessagePattern<span class="token punctuation">,</span> Payload <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/microservices&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Controller</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisController</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token keyword">private</span> <span class="token keyword">readonly</span> analysisService<span class="token operator">:</span> AnalysisService<span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token comment">// 原有的 HTTP 接口</span>
  <span class="token decorator"><span class="token at operator">@</span><span class="token function">Post</span></span><span class="token punctuation">(</span><span class="token string">&#39;text&#39;</span><span class="token punctuation">)</span>
  <span class="token keyword">async</span> <span class="token function">analyzeText</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">Body</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> analyzeTextDto<span class="token operator">:</span> AnalyzeTextDto<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      success<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
      data<span class="token operator">:</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisService<span class="token punctuation">.</span><span class="token function">analyzeText</span><span class="token punctuation">(</span>analyzeTextDto<span class="token punctuation">.</span>content<span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token comment">// 新增的微服务接口 (Redis Transport)</span>
  <span class="token comment">// 其他微服务可以通过 ClientProxy.send({ cmd: &#39;analyze_text_microservice&#39; }, data) 进行 RPC 调用</span>
  <span class="token decorator"><span class="token at operator">@</span><span class="token function">MessagePattern</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> cmd<span class="token operator">:</span> <span class="token string">&#39;analyze_text_microservice&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token keyword">async</span> <span class="token function">handleAnalyzeTextMicroservice</span><span class="token punctuation">(</span><span class="token decorator"><span class="token at operator">@</span><span class="token function">Payload</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> data<span class="token operator">:</span> <span class="token punctuation">{</span> content<span class="token operator">:</span> <span class="token builtin">string</span> <span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    Logger<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">收到微服务调用请求: analyze_text_microservice</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisService<span class="token punctuation">.</span><span class="token function">analyzeText</span><span class="token punctuation">(</span>data<span class="token punctuation">.</span>content<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      success<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
      data<span class="token operator">:</span> result<span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-结合消息队列-message-queues-的全景架构" tabindex="-1"><a class="header-anchor" href="#_3-结合消息队列-message-queues-的全景架构" aria-hidden="true">#</a> 3. 结合消息队列 (Message Queues) 的全景架构</h2><p>结合我们在之前章节实现的 <strong>BullMQ 异步队列</strong> (<code>@nestjs/bullmq</code>)，我们现在拥有了一个非常健壮的高并发处理架构：</p><ol><li><strong>API 网关/控制器</strong>：接收到耗时的上传请求（<code>upload-async</code>），快速进行数据校验，并将任务推入 BullMQ 队列，立即返回 HTTP 200。</li><li><strong>缓存拦截</strong>：核心处理逻辑执行前，先进行哈希计算，如果 Redis 中已有缓存结果，直接返回，跳过昂贵的大模型调用。</li><li><strong>后台处理器 (Processor)</strong>：独立于主 HTTP 线程，慢慢消化队列中的任务，调用大模型。</li><li><strong>微服务 RPC (可选)</strong>：如果系统规模进一步扩大，可以将 AI 处理逻辑完全剥离为独立的微服务集群，通过 Redis Transport 与 API 网关进行高效内部通信。</li></ol><p>通过这套组合拳（<strong>Redis Caching + BullMQ + Microservices</strong>），我们的 AI Agent 后端已经具备了处理生产级别高并发、大数据量请求的能力。</p>`,27)])])}const l=s(e,[["render",o],["__file","5.1 Nest.js后端性能优化与微服务架构.html.vue"]]);export{l as default};
